class Shape {
  constructor({ x = 0, y = 0, color = 'black' } = {}) {
    this.x = x;
    this.y = y;
    this.color = color;
  }

  clone() {
    return new this.constructor({ ...this });
  }
}

class Circle extends Shape {
  constructor({ x, y, color, radius = 0 } = {}) {
    super({ x, y, color });
    this.radius = radius;
  }
}

class Rectangle extends Shape {
  constructor({ x, y, color, width = 0, height = 0 } = {}) {
    super({ x, y, color });
    this.width = width;
    this.height = height;
  }
}

// Usage
const original = new Circle({ x: 10, y: 20, color: 'red', radius: 15 });
const copy = original.clone();

copy.color = 'blue';

console.log(original.color);      // red  — original unchanged
console.log(copy.color);          // blue
console.log(copy instanceof Circle); // true

